#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long x,y;
    bool operator<(const node&b)const
    {
        if(x==b.x)
        {
            return y<b.y;
        }
        return x<b.x;
    }
}p[400010];
long long n,k,cnt;
vector<long long> ans;
multiset<pair<long long,long long>> s;
bool check(long long mid)
{
    ans.clear();
    s.clear();
    long long pos=1;
    cnt=0;
    for(long long i=1;i<=n;i++)
    {
        if(i>1)
        {
            s.insert({p[i-1].y,i-1});
        }
        while(p[i].x-p[pos].x>mid)
        {
            s.erase({p[pos].y,pos});
            pos++;
        }
        auto it=s.lower_bound({p[i].y-mid,0});
        while(it!=s.end()&&it->first<=p[i].y+mid)
        {
            cnt++;
            ans.push_back(max(abs(p[i].y-it->first),abs(p[i].x-p[it->second].x)));
            it++;
            if(cnt>k)
            {
                return false;
            }
        }
    }
    return true;
}
int main()
{
    scanf("%lld%lld",&n,&k);
    for(long long i=1;i<=n;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        p[i].x=x+y;
        p[i].y=x-y;
    }
    sort(p+1,p+1+n);
    long long l=1,r=4e9,best=0;
    while(l<=r)
    {
        long long mid=(l+r)>>1;
        if(check(mid))
        {
            best=mid;
            l=mid+1;
        }
        else
        {
            r=mid-1;
        }
    }
    check(best);
    for(long long i=cnt+1;i<=k;i++)
    {
        ans.push_back(best+1);
    }
    sort(ans.begin(),ans.end());
    for(long long i:ans)
    {
        printf("%lld\n",i);
    }
    return 0;
}
